"use client";

import { FC } from "react";
import Image from "next/image";

interface ImageSliderProps {
  images: { id: number; src: string; alt: string }[];
}

const ImageSlider: FC<ImageSliderProps> = ({ images }) => {
  const mainImage = images[0]; // Main image displayed prominently
  const previewImages = images.slice(1); // Remaining images as previews

  return (
    <div className="image-slider">
      <div className="main-image">
        <Image
          src={mainImage.src}
          alt={mainImage.alt}
          width={800}
          height={600}
          className="w-full h-auto object-cover rounded-lg"
        />
      </div>
      <div className="preview-cards">
        {previewImages.map((image) => (
          <div key={image.id} className="preview-card">
            <Image
              src={image.src}
              alt={image.alt}
              width={200}
              height={150}
              className="w-full h-full object-cover rounded-lg cursor-pointer hover:opacity-80"
            />
          </div>
        ))}
      </div>
    </div>
  );
};

export default ImageSlider;